+/**
+ * Draws a medieval parchment-style tooltip near the given position.
+ * Shows character name, role, current status, and current task.
+ */
+export function drawTooltip(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  width: number,
+  height: number,
+  name: string,
+  role: string,
+  status: string,
+  task: string | null,
+) {
+  const padding = 8;
+  const cornerRadius = 12;
+  const shadowColor = 'rgba(0,0,0,0.4)';
+  const parchmentColor = '#f5e6a1';
+  const parchmentBorder = '#c9b86a';
+  const textColor = '#3a2a00';
+  const lineHeight = 16;
+
+  // Draw parchment background with shadow
+  ctx.save();
+  ctx.shadowColor = shadowColor;
+  ctx.shadowBlur = 8;
+  ctx.shadowOffsetX = 2;
+  ctx.shadowOffsetY = 2;
+  ctx.fillStyle = parchmentColor;
+  roundRect(ctx, x, y, width, height, cornerRadius);
+  ctx.fill();
+  ctx.shadowColor = 'transparent';
+  ctx.strokeStyle = parchmentBorder;
+  ctx.lineWidth = 2;
+  roundRect(ctx, x, y, width, height, cornerRadius);
+  ctx.stroke();
+
+  // Draw decorative scroll edges (top and bottom)
+  const edgeHeight = 6;
+  const edgeWidth = 12;
+  ctx.fillStyle = parchmentBorder;
+  for (let i = 0; i < width; i += edgeWidth * 2) {
+    // top edge curls
+    ctx.beginPath();
+    ctx.moveTo(x + i, y);
+    ctx.bezierCurveTo(x + i + edgeWidth / 2, y - edgeHeight, x + i + edgeWidth * 1.5, y - edgeHeight, x + i + edgeWidth * 2, y);
+    ctx.lineTo(x + i + edgeWidth * 2, y + 2);
+    ctx.bezierCurveTo(x + i + edgeWidth * 1.5, y - edgeHeight + 2, x + i + edgeWidth / 2, y - edgeHeight + 2, x + i, y + 2);
+    ctx.closePath();
+    ctx.fill();
+
+    // bottom edge curls
+    ctx.beginPath();
+    ctx.moveTo(x + i, y + height);
+    ctx.bezierCurveTo(x + i + edgeWidth / 2, y + height + edgeHeight, x + i + edgeWidth * 1.5, y + height + edgeHeight, x + i + edgeWidth * 2, y + height);
+    ctx.lineTo(x + i + edgeWidth * 2, y + height - 2);
+    ctx.bezierCurveTo(x + i + edgeWidth * 1.5, y + height + edgeHeight - 2, x + i + edgeWidth / 2, y + height + edgeHeight - 2, x + i, y + height - 2);
+    ctx.closePath();
+    ctx.fill();
+  }
+
+  // Draw text lines
+  ctx.fillStyle = textColor;
+  ctx.font = 'bold 14px serif';
+  ctx.textBaseline = 'top';
+  ctx.fillText(name, x + padding, y + padding);
+  ctx.font = 'italic 12px serif';
+  ctx.fillText(role, x + padding, y + padding + lineHeight);
+  ctx.font = '12px serif';
+  ctx.fillText(`Status: ${status}`, x + padding, y + padding + lineHeight * 2);
+  ctx.fillText(`Task: ${task ?? 'None'}`, x + padding, y + padding + lineHeight * 3);
+
+  ctx.restore();
+}
+
+/**
+ * Checks if mouse is near a character position within a threshold.
+ * Returns true if within threshold distance.
+ */
+export function isMouseNearCharacter(
+  mouseX: number,
+  mouseY: number,
+  charX: number,
+  charY: number,
+  threshold: number,
+): boolean {
+  const dx = mouseX - charX;
+  const dy = mouseY - charY;
+  return dx * dx + dy * dy <= threshold * threshold;
+}
