+interface AgentInfo {
+  id: string;
+  name: string;
+  tier: string;
+  state: string;
+  currentJob: string | null;
+}
+
+interface RoomSlot {
+  tier: CharacterType;
+  label: string;
+  col: number;
+  row: number;
+}
+
+const ROOM_GRID: RoomSlot[] = [
+  { tier: 'king',       label: 'Throne Room',   col: 1, row: 0 },
+  { tier: 'nobility',   label: 'Council Hall',  col: 0, row: 1 },
+  { tier: 'knight',     label: 'War Room',      col: 1, row: 1 },
+  { tier: 'sentinel',   label: 'Watchtower',    col: 2, row: 1 },
+  { tier: 'squire',     label: 'Workshop',      col: 0, row: 2 },
+  { tier: 'healer',     label: 'Sanctum',       col: 1, row: 2 },
+  { tier: 'blacksmith', label: 'Forge',         col: 2, row: 2 },
+  { tier: 'scribe',     label: 'Scriptorium',   col: 0, row: 3 },
+  { tier: 'judge',      label: 'Tribunal',      col: 1, row: 3 },
+];
+
+const DEFAULT_AGENTS: AgentInfo[] = [
+  { id: '1', name: 'The Crown',      tier: 'king',       state: 'idle', currentJob: null },
+  { id: '2', name: 'Lord Regent',    tier: 'nobility',   state: 'idle', currentJob: null },
+  { id: '3', name: 'Sir Galahad',    tier: 'knight',     state: 'idle', currentJob: null },
+  { id: '4', name: 'Page Turner',    tier: 'squire',     state: 'idle', currentJob: null },
+  { id: '5', name: 'Brother Aldric', tier: 'healer',     state: 'idle', currentJob: null },
+  { id: '6', name: 'Night Watch',    tier: 'sentinel',   state: 'idle', currentJob: null },
+  { id: '7', name: 'Chronicler',     tier: 'scribe',     state: 'idle', currentJob: null },
+  { id: '8', name: 'Lord Justice',   tier: 'judge',      state: 'idle', currentJob: null },
+  { id: '9', name: 'Iron Forge',     tier: 'blacksmith', state: 'idle', currentJob: null },
+];
+
+export function AgentsScene() {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+  const [mousePos, setMousePos] = useState<{ x: number; y: number } | null>(null);
+
+  // Poll agents every 5 seconds
+  useEffect(() => {
+    let active = true;
+    const poll = () => {
+      fetch('/api/agents')
+        .then((r) => r.ok ? r.json() : [])
+        .then((data: AgentInfo[]) => {
+          if (active && Array.isArray(data) && data.length > 0) setAgents(data);
+        })
+        .catch(() => {});
+    };
+    poll();
+    const iv = setInterval(poll, 5000);
+    return () => {
+      active = false;
+      clearInterval(iv);
+    };
+  }, []);
+
+  // Track mouse position on canvas
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+    function onMouseMove(e: MouseEvent) {
+      const rect = canvas.getBoundingClientRect();
+      setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
+    }
+    function onMouseLeave() {
+      setMousePos(null);
+    }
+    canvas.addEventListener('mousemove', onMouseMove);
+    canvas.addEventListener('mouseleave', onMouseLeave);
+    return () => {
+      canvas.removeEventListener('mousemove', onMouseMove);
+      canvas.removeEventListener('mouseleave', onMouseLeave);
+    };
+  }, []);
+
+  useEffect(() => {
+    if (!canvasRef.current) return;
+
+    const cancel = startGameLoop((dt, frameCount) => {
+      const rc = syncCanvasSize(canvasRef.current!);
+      clearCanvas(rc);
+
+      const cols = 3;
+      const padding = 10;
+      const labelH = 24;
+      const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+      const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+      // Group agents by tier
+      const agentsByTier = new Map<string, AgentInfo[]>();
+      for (const a of agents) {
+        const list = agentsByTier.get(a.tier) ?? [];
+        list.push(a);
+        agentsByTier.set(a.tier, list);
+      }
+
+      // To store agent draw positions for tooltip detection
+      const agentDrawPositions: { agent: AgentInfo; x: number; y: number; scale: number }[] = [];
+
+      for (const slot of ROOM_GRID) {
+        const rx = padding + slot.col * (roomW + padding);
+        const ry = padding + slot.row * (roomH + labelH + padding + 6);
+
+        // Room label with shadow
+        drawText(rc, slot.label.toUpperCase(), rx + 5, ry + 15, 11, '#000000');
+        drawText(rc, slot.label.toUpperCase(), rx + 4, ry + 14, 11, '#ffd700');
+
+        // Room background
+        drawRoom(rc.ctx, slot.tier, rx, ry + labelH, roomW, roomH, frameCount);
+
+        // Room border (double line for depth)
+        rc.ctx.strokeStyle = '#2a2030';
+        rc.ctx.lineWidth = 2;
+        rc.ctx.strokeRect(rx, ry + labelH, roomW, roomH);
+        rc.ctx.strokeStyle = '#5a5a6a';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx + 1, ry + labelH + 1, roomW - 2, roomH - 2);
+
+        // Draw agents in this room (cap visible at 4, show overflow badge)
+        const tierAgents = agentsByTier.get(slot.tier) ?? [];
+        const maxVisible = 4;
+        const visible = tierAgents.slice(0, maxVisible);
+        const overflow = tierAgents.length - visible.length;
+        const charScale = Math.min(2.5, roomW / 90);
+
+        visible.forEach((agent, i) => {
+          // Determine target position based on agent state
+          let targetX: number;
+          let targetY: number;
+
+          if (agent.state === 'running') {
+            // Position at workstation furniture
+            const wsPos = getWorkstationPosition(slot.tier);
+            targetX = rx + roomW * wsPos.x;
+            targetY = ry + labelH + roomH * wsPos.y;
+          } else {
+            // Idle: random spread within walkable area
+            const spreadX = roomW * 0.7;
+            const spreadY = roomH * 0.45;
+            targetX = rx + roomW * 0.15 + i * Math.min(55, spreadX / Math.max(1, visible.length));
+            targetY = ry + labelH + roomH * 0.45;
+          }
+
+          // Get current character state and smoothly update position
+          const cs = getCS(agent.id, targetX, targetY);
+
+          // Smoothly update position towards target
+          const updatedPos = updateCharacterPosition(agent.id, cs.x, cs.y, targetX, targetY, dt);
+          cs.x = updatedPos.x;
+          cs.y = updatedPos.y;
+
+          // Draw character with updated position and pass state
+          drawCharacter(
+            rc.ctx,
+            slot.tier as CharacterType,
+            agent.state as AnimState,
+            cs.x,
+            cs.y,
+            charScale,
+            frameCount,
+            agent.id,
+            agent.currentJob,
+          );
+
+          // Name plate (below character)
+          const nameY = cs.y + 24 * charScale;
+          drawText(rc, agent.name, cs.x - 4, nameY, 9, '#fff');
+          // State badge
+          drawText(rc, agent.state, cs.x - 4, nameY + 12, 8, '#ccc');
+
+          // Save draw position for tooltip detection
+          agentDrawPositions.push({ agent, x: cs.x, y: cs.y, scale: charScale });
+        });
+
+        // Overflow badge
+        if (overflow > 0) {
+          const badgeX = rx + roomW - 30;
+          const badgeY = ry + labelH + 8;
+          rc.ctx.fillStyle = '#4a2060';
+          rc.ctx.fillRect(badgeX, badgeY, 24, 14);
+          rc.ctx.strokeStyle = '#ffd700';
+          rc.ctx.lineWidth = 1;
+          rc.ctx.strokeRect(badgeX, badgeY, 24, 14);
+          drawText(rc, `+${overflow}`, badgeX + 3, badgeY + 11, 9, '#ffd700');
+        }
+
+        if (tierAgents.length === 0) {
+          drawText(rc, '— vacant —', rx + roomW * 0.3, ry + labelH + roomH * 0.55, 10, '#555');
+        }
+      }
+
+      // Draw tooltip if mouse near any agent
+      if (mousePos) {
+        const threshold = 40;
+        for (const { agent, x, y, scale } of agentDrawPositions) {
+          if (isMouseNearCharacter(mousePos.x, mousePos.y, x, y, threshold)) {
+            const tooltipWidth = 160;
+            const tooltipHeight = 80;
+            let tx = mousePos.x + 12;
+            let ty = mousePos.y + 12;
+            // Keep tooltip inside canvas bounds
+            if (tx + tooltipWidth > rc.width) tx = mousePos.x - tooltipWidth - 12;
+            if (ty + tooltipHeight > rc.height) ty = mousePos.y - tooltipHeight - 12;
+            drawTooltip(
+              rc.ctx,
+              tx,
+              ty,
+              tooltipWidth,
+              tooltipHeight,
+              agent.name,
+              agent.tier.charAt(0).toUpperCase() + agent.tier.slice(1),
+              agent.state,
+              agent.currentJob,
+            );
+            break;
+          }
+        }
+      }
+    });
+
+    return cancel;
+  }, [agents, mousePos]);
+
+  return (
+    <canvas
+      ref={canvasRef}
+      style={{ display: 'block', width: '100%', height: 'calc(100vh - 40px)' }}
+    />
+  );
+}
+
